// frontend/src/components/Dashboard/FinishedOperationsModal.js
import React, { useState, useEffect } from 'react';
import {
  Dialog,
  DialogTitle,
  DialogContent,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Paper,
  Typography,
  Box,
  Chip,
  IconButton,
  Tooltip,
  CircularProgress,
  useTheme,
  Button,
  TextField,
  MenuItem,
  Grid
} from '@mui/material';
import {
  Close,
  TrendingUp,
  TrendingDown,
  Refresh,
  FilterList,
  Download
} from '@mui/icons-material';
import dashboardService from '../../services/dashboardService';

const FinishedOperationsModal = ({ open, onClose, hideValues = false }) => {
  const theme = useTheme();
  const [finishedTrades, setFinishedTrades] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [filters, setFilters] = useState({
    symbol: '',
    side: '',
    dateFrom: '',
    dateTo: ''
  });

  useEffect(() => {
    if (open) {
      loadFinishedTrades();
    }
  }, [open]);

  const loadFinishedTrades = async () => {
    try {
      setLoading(true);
      setError('');

      // Por enquanto, vamos simular dados até implementar o endpoint
      // const response = await dashboardService.getFinishedTrades(filters);

      // Dados simulados para demonstração
      const mockData = [
        {
          id: 1,
          symbol: 'BTCUSDT',
          side: 'long',
          size: '0.1',
          entry_price: '45000.00',
          exit_price: '46500.00',
          leverage: 10,
          pnl: 150.00,
          roe: 33.33,
          fees: 5.50,
          margin: 450.00,
          opened_at: '2024-01-15T10:30:00Z',
          closed_at: '2024-01-15T14:20:00Z',
          status: 'closed'
        },
        {
          id: 2,
          symbol: 'ETHUSDT',
          side: 'short',
          size: '2.5',
          entry_price: '2800.00',
          exit_price: '2750.00',
          leverage: 5,
          pnl: 125.00,
          roe: 17.86,
          fees: 3.75,
          margin: 700.00,
          opened_at: '2024-01-14T08:15:00Z',
          closed_at: '2024-01-14T16:45:00Z',
          status: 'closed'
        },
        {
          id: 3,
          symbol: 'ADAUSDT',
          side: 'long',
          size: '1000',
          entry_price: '0.5200',
          exit_price: '0.4950',
          leverage: 8,
          pnl: -25.00,
          roe: -4.81,
          fees: 2.10,
          margin: 520.00,
          opened_at: '2024-01-13T12:00:00Z',
          closed_at: '2024-01-13T18:30:00Z',
          status: 'closed'
        }
      ];

      setFinishedTrades(mockData);
    } catch (error) {
      console.error('Erro ao carregar operações finalizadas:', error);
      setError(error.message || 'Erro ao carregar operações finalizadas');
    } finally {
      setLoading(false);
    }
  };

  const formatCurrency = (value) => {
    if (hideValues) return '$***';
    if (value === null || value === undefined) return '$0.00';
    return new Intl.NumberFormat('en-US', {
      style: 'currency',
      currency: 'USD',
      minimumFractionDigits: 2,
      maximumFractionDigits: 4
    }).format(value);
  };

  const formatPercentage = (value) => {
    if (hideValues) return '***%';
    if (value === null || value === undefined) return '0.00%';
    const sign = value >= 0 ? '+' : '';
    return `${sign}${value.toFixed(2)}%`;
  };

  const formatDate = (dateString) => {
    if (!dateString) return '-';
    return new Date(dateString).toLocaleString('pt-BR', {
      day: '2-digit',
      month: '2-digit',
      year: 'numeric',
      hour: '2-digit',
      minute: '2-digit'
    });
  };

  const getPnlColor = (pnl) => {
    if (pnl > 0) return theme.palette.success.main;
    if (pnl < 0) return theme.palette.error.main;
    return theme.palette.text.secondary;
  };

  const getSideColor = (side) => {
    return side === 'long' ? theme.palette.success.main : theme.palette.error.main;
  };

  const handleFilterChange = (field, value) => {
    setFilters(prev => ({ ...prev, [field]: value }));
  };

  const applyFilters = () => {
    loadFinishedTrades();
  };

  const clearFilters = () => {
    setFilters({
      symbol: '',
      side: '',
      dateFrom: '',
      dateTo: ''
    });
    loadFinishedTrades();
  };

  const exportTrades = () => {
    // Implementar exportação para CSV/Excel
    console.log('Exportar operações finalizadas');
  };

  return (
    <Dialog
      open={open}
      onClose={onClose}
      maxWidth="xl"
      fullWidth
      PaperProps={{
        sx: {
          backgroundColor: '#1C2127',
          color: 'white',
          minHeight: '80vh'
        }
      }}
    >
      <DialogTitle sx={{ 
        display: 'flex', 
        justifyContent: 'space-between', 
        alignItems: 'center',
        borderBottom: '1px solid rgba(255, 255, 255, 0.1)',
        pb: 2
      }}>
        <Typography variant="h6" component="div" sx={{ fontWeight: 'bold' }}>
          Operações Finalizadas
        </Typography>
        <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
          <Tooltip title="Exportar dados">
            <IconButton onClick={exportTrades} sx={{ color: 'white' }}>
              <Download />
            </IconButton>
          </Tooltip>
          <Tooltip title="Atualizar">
            <IconButton onClick={loadFinishedTrades} disabled={loading} sx={{ color: 'white' }}>
              <Refresh />
            </IconButton>
          </Tooltip>
          <IconButton onClick={onClose} sx={{ color: 'white' }}>
            <Close />
          </IconButton>
        </Box>
      </DialogTitle>

      <DialogContent sx={{ p: 3 }}>
        {/* Filtros */}
        <Box sx={{ mb: 3, p: 2, backgroundColor: 'rgba(255, 255, 255, 0.05)', borderRadius: 2 }}>
          <Typography variant="subtitle2" sx={{ mb: 2, display: 'flex', alignItems: 'center' }}>
            <FilterList sx={{ mr: 1 }} />
            Filtros
          </Typography>
          <Grid container spacing={2}>
            <Grid item xs={12} sm={6} md={3}>
              <TextField
                fullWidth
                size="small"
                label="Símbolo"
                value={filters.symbol}
                onChange={(e) => handleFilterChange('symbol', e.target.value)}
                placeholder="Ex: BTCUSDT"
                sx={{ 
                  '& .MuiOutlinedInput-root': { color: 'white' },
                  '& .MuiInputLabel-root': { color: 'rgba(255, 255, 255, 0.7)' },
                  '& .MuiOutlinedInput-notchedOutline': { borderColor: 'rgba(255, 255, 255, 0.3)' }
                }}
              />
            </Grid>
            <Grid item xs={12} sm={6} md={3}>
              <TextField
                fullWidth
                size="small"
                select
                label="Lado"
                value={filters.side}
                onChange={(e) => handleFilterChange('side', e.target.value)}
                sx={{ 
                  '& .MuiOutlinedInput-root': { color: 'white' },
                  '& .MuiInputLabel-root': { color: 'rgba(255, 255, 255, 0.7)' },
                  '& .MuiOutlinedInput-notchedOutline': { borderColor: 'rgba(255, 255, 255, 0.3)' }
                }}
              >
                <MenuItem value="">Todos</MenuItem>
                <MenuItem value="long">Long</MenuItem>
                <MenuItem value="short">Short</MenuItem>
              </TextField>
            </Grid>
            <Grid item xs={12} sm={6} md={2}>
              <Button
                fullWidth
                variant="outlined"
                onClick={applyFilters}
                sx={{ height: '40px' }}
              >
                Aplicar
              </Button>
            </Grid>
            <Grid item xs={12} sm={6} md={2}>
              <Button
                fullWidth
                variant="text"
                onClick={clearFilters}
                sx={{ height: '40px' }}
              >
                Limpar
              </Button>
            </Grid>
          </Grid>
        </Box>

        {/* Tabela de Operações */}
        {loading ? (
          <Box sx={{ display: 'flex', justifyContent: 'center', py: 4 }}>
            <CircularProgress sx={{ color: '#00d4ff' }} />
          </Box>
        ) : error ? (
          <Box sx={{ textAlign: 'center', py: 4 }}>
            <Typography color="error">{error}</Typography>
          </Box>
        ) : (
          <TableContainer component={Paper} sx={{ backgroundColor: 'transparent' }}>
            <Table>
              <TableHead>
                <TableRow sx={{ '& th': { borderBottom: '1px solid rgba(255, 255, 255, 0.1)' } }}>
                  <TableCell sx={{ color: 'white', fontWeight: 'bold' }}>Símbolo</TableCell>
                  <TableCell sx={{ color: 'white', fontWeight: 'bold' }}>Lado</TableCell>
                  <TableCell sx={{ color: 'white', fontWeight: 'bold' }}>Tamanho</TableCell>
                  <TableCell sx={{ color: 'white', fontWeight: 'bold' }}>Entrada</TableCell>
                  <TableCell sx={{ color: 'white', fontWeight: 'bold' }}>Saída</TableCell>
                  <TableCell sx={{ color: 'white', fontWeight: 'bold' }}>Leverage</TableCell>
                  <TableCell sx={{ color: 'white', fontWeight: 'bold' }}>PnL</TableCell>
                  <TableCell sx={{ color: 'white', fontWeight: 'bold' }}>ROE</TableCell>
                  <TableCell sx={{ color: 'white', fontWeight: 'bold' }}>Fechado em</TableCell>
                </TableRow>
              </TableHead>
              <TableBody>
                {finishedTrades.map((trade) => (
                  <TableRow 
                    key={trade.id}
                    sx={{ 
                      '& td': { borderBottom: '1px solid rgba(255, 255, 255, 0.05)' },
                      '&:hover': { backgroundColor: 'rgba(255, 255, 255, 0.02)' }
                    }}
                  >
                    <TableCell sx={{ color: 'white', fontWeight: 'bold' }}>
                      {trade.symbol}
                    </TableCell>
                    <TableCell>
                      <Chip
                        label={trade.side.toUpperCase()}
                        size="small"
                        sx={{
                          backgroundColor: `${getSideColor(trade.side)}20`,
                          color: getSideColor(trade.side),
                          fontWeight: 'bold'
                        }}
                      />
                    </TableCell>
                    <TableCell sx={{ color: 'white' }}>
                      {hideValues ? '***' : trade.size}
                    </TableCell>
                    <TableCell sx={{ color: 'white' }}>
                      {formatCurrency(trade.entry_price)}
                    </TableCell>
                    <TableCell sx={{ color: 'white' }}>
                      {formatCurrency(trade.exit_price)}
                    </TableCell>
                    <TableCell sx={{ color: 'white' }}>
                      {trade.leverage}x
                    </TableCell>
                    <TableCell>
                      <Box sx={{ display: 'flex', alignItems: 'center' }}>
                        {trade.pnl > 0 ? (
                          <TrendingUp sx={{ color: theme.palette.success.main, mr: 0.5, fontSize: 18 }} />
                        ) : trade.pnl < 0 ? (
                          <TrendingDown sx={{ color: theme.palette.error.main, mr: 0.5, fontSize: 18 }} />
                        ) : null}
                        <Typography
                          variant="body2"
                          sx={{ 
                            color: getPnlColor(trade.pnl),
                            fontWeight: 'bold'
                          }}
                        >
                          {formatCurrency(trade.pnl)}
                        </Typography>
                      </Box>
                    </TableCell>
                    <TableCell>
                      <Typography
                        variant="body2"
                        sx={{ 
                          color: getPnlColor(trade.roe),
                          fontWeight: 'bold'
                        }}
                      >
                        {formatPercentage(trade.roe)}
                      </Typography>
                    </TableCell>
                    <TableCell sx={{ color: 'rgba(255, 255, 255, 0.7)' }}>
                      {formatDate(trade.closed_at)}
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>

            {finishedTrades.length === 0 && (
              <Box sx={{ textAlign: 'center', py: 4 }}>
                <Typography color="text.secondary">
                  Nenhuma operação finalizada encontrada
                </Typography>
              </Box>
            )}
          </TableContainer>
        )}
      </DialogContent>
    </Dialog>
  );
};

export default FinishedOperationsModal;
